    # Check for automaton (b is a subsequence of n)
    i = j = 0
    while i < len(n) and j < len(b):
        if n[i] == b[j]:
            j += 1
        i += 1
    automaton = (j == len(b))

    # Check for array (same characters with same counts)
    from collections import defaultdict
    count_n = defaultdict(int)
    count_b = defaultdict(int)
