    for c in b:
        count_b[c] += 1
    array = True
    for c in count_b:
        if count_n[c] < count_b[c]:
            array = False
            break

    if automaton:
        print("automaton")
    elif array:
        if len(n) == len(b):
            print("array")
        else:
            print("both")
    else:
        print("need tree")
